const DoughnutChart: React.FC<{ data: number[], colors: string[], labels: string[], cutout?: string }> = ({ data, colors, labels, cutout = '75%' }) => {
    const canvasRef = useRef<HTMLCanvasElement | null>(null);
    const chartRef = useRef<Chart | null>(null);

    useEffect(() => {
        if (!canvasRef.current) return;
        if (chartRef.current) chartRef.current.destroy();
        const ctx = canvasRef.current.getContext('2d');
        if (!ctx) return;
        chartRef.current = new Chart(ctx, {
            type: 'doughnut',
            data: {
                labels,
                datasets: [{ 
                    data, 
                    backgroundColor: colors, 
                    borderColor: 'rgba(15, 23, 42, 1)', 
                    borderWidth: 2,
                    hoverOffset: 4
                }]
            },
            options: {
                responsive: true, 
                maintainAspectRatio: false, 
                cutout,
                plugins: { legend: { display: false } }
            }
        });
        return () => chartRef.current?.destroy();
    }, [data, labels, colors, cutout]);
    return <div className="h-full w-full"><canvas ref={canvasRef}></canvas></div>;
};

const MonthDetailView: React.FC<{ 
    year: number; 
    month: number; 
    monthName: string;
    onBack: () => void;
}> = ({ year, month, monthName, onBack }) => {
    const [activeTab, setActiveTab] = useState<'income' | 'expense'>('expense');
    const [loading, setLoading] = useState(false);
    const [data, setData] = useState<{ totalIncome: number; totalExpense: number; incomeCategories: any[]; expenseCategories: any[]; }>({
        totalIncome: 0, totalExpense: 0, incomeCategories: [], expenseCategories: []
    });

    useEffect(() => {
        const fetchDetails = async () => {
            setLoading(true);
            const startDate = new Date(year, month, 1);
            const endDate = new Date(year, month + 1, 0, 23, 59, 59);

            const { data: txs } = await supabase
                .from('transactions')
                .select('amount, type, categories(name, color, icon)')
                .gte('date', startDate.toISOString())
                .lte('date', endDate.toISOString())
                .in('type', ['income', 'expense']);

            let tIncome = 0, tExpense = 0;
            const incMap = new Map<string, any>(), expMap = new Map<string, any>();

            txs?.forEach((tx: any) => {
                const catName = tx.categories?.name || 'غير مصنف';
                const catColor = tx.categories?.color || '#64748b';
                const catIcon = tx.categories?.icon;

                if (tx.type === 'income') {
                    tIncome += tx.amount;
                    const c = incMap.get(catName) || { name: catName, amount: 0, count: 0, color: catColor, icon: catIcon };
                    c.amount += tx.amount;
                    c.count += 1;
                    incMap.set(catName, c);
                } else {
                    tExpense += tx.amount;
                    const c = expMap.get(catName) || { name: catName, amount: 0, count: 0, color: catColor, icon: catIcon };
                    c.amount += tx.amount;
                    c.count += 1;
                    expMap.set(catName, c);
                }
            });

            const process = (map: Map<string, any>, total: number) => 
                Array.from(map.values())
                    .map(c => ({ ...c, percentage: total > 0 ? (c.amount / total) * 100 : 0 }))
                    .sort((a, b) => b.amount - a.amount);

            setData({ 
                totalIncome: tIncome, 
                totalExpense: tExpense, 
                incomeCategories: process(incMap, tIncome), 
                expenseCategories: process(expMap, tExpense) 
            });
            setLoading(false);
        };
        fetchDetails();
    }, [year, month]);

    const activeCategories = activeTab === 'expense' ? data.expenseCategories : data.incomeCategories;

    return (
        <div className="space-y-6 animate-fade-in pb-10">
            <div className="flex items-center gap-4 mb-2">
                <button onClick={onBack} className="p-2 bg-slate-800 rounded-xl text-slate-400 hover:text-white transition">
                    <ArrowRightIcon className="w-5 h-5" />
                </button>
                <div>
                    <h4 className="text-xl font-black text-white">تفاصيل شهر {monthName}</h4>
                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{year}</p>
                </div>
            </div>

            <div className="flex bg-slate-800/80 p-1.5 rounded-2xl border border-white/5 shadow-inner">
                <button onClick={() => setActiveTab('expense')} className={`flex-1 py-3 rounded-xl text-sm font-black transition-all flex items-center justify-center gap-2 ${activeTab === 'expense' ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-500'}`}>
                    <ArrowUpIcon className="w-4 h-4"/> المصروفات
                </button>
                <button onClick={() => setActiveTab('income')} className={`flex-1 py-3 rounded-xl text-sm font-black transition-all flex items-center justify-center gap-2 ${activeTab === 'income' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500'}`}>
                    <ArrowDownIcon className="w-4 h-4"/> الإيرادات
                </button>
            </div>

            {loading ? (
                <div className="space-y-3">
                    {[1,2,3].map(i => <div key={i} className="h-20 bg-slate-800/50 rounded-3xl animate-pulse"></div>)}
                </div>
            ) : activeCategories.length > 0 ? (
                <div className="space-y-3">
                    {activeCategories.map((cat, i) => {
                        const Icon = (cat.icon && iconMap[cat.icon]) ? iconMap[cat.icon] : TagIcon;
                        return (
                            <div key={i} className="bg-slate-900/60 p-4 rounded-3xl border border-white/5 transition-all hover:bg-slate-800/60 group">
                                <div className="flex items-center gap-4 mb-3">
                                    <div className="w-12 h-12 rounded-2xl flex items-center justify-center text-white shrink-0 shadow-lg" style={{ backgroundColor: cat.color }}>
                                        <Icon className="w-6 h-6" />
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <div className="flex justify-between items-center mb-1">
                                            <span className="text-sm font-bold text-white truncate">{cat.name}</span>
                                            <span className="text-sm font-black text-white tabular-nums">{new Intl.NumberFormat('ar-LY').format(cat.amount)} د.ل</span>
                                        </div>
                                        <div className="flex justify-between items-center text-[10px] font-bold text-slate-500">
                                            <span>{cat.count} عمليات مسجلة</span>
                                            <span>{cat.percentage.toFixed(1)}%</span>
                                        </div>
                                    </div>
                                </div>
                                <div className="h-1.5 bg-slate-800 rounded-full overflow-hidden">
                                    <div className="h-full transition-all duration-1000 ease-out rounded-full" style={{ width: `${cat.percentage}%`, backgroundColor: cat.color }}></div>
                                </div>
