const AddCategoryModal: React.FC<{ onSuccess: (newCategoryId?: string) => void; onCancel: () => void; initialType?: 'income' | 'expense'; isInline?: boolean }> = ({ onSuccess, onCancel, initialType = 'expense', isInline = false }) => {
