            logActivity(`إنشاء فئة جديدة: ${name} (${type === 'income' ? 'دخل' : 'مصروف'})`);
            onSuccess(data.id);
        }
        setIsSaving(false);
    };

    const IconComp = iconMap[icon] || TagIcon;

    return (
        <form onSubmit={handleSubmit} className={`space-y-6 ${isInline ? 'animate-fade-in' : ''}`}>
