                    <button type="button" onClick={() => setType('income')} className={`flex-1 py-3 rounded-xl font-black text-xs transition-all ${type === 'income' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500'}`}>فئة دخل</button>
