      <div className="flex flex-col items-center gap-6 relative z-10 w-full max-w-[200px]">
        {/* شريط تحميل نحيف جداً وأنيق */}
        <div className="h-[1px] w-full bg-slate-900 rounded-full overflow-hidden">
          <div className="h-full bg-gradient-to-r from-transparent via-cyan-500 to-transparent w-1/2 animate-shimmer-bar"></div>
        </div>

        {/* النص المتموج المتغير */}
